  ('heelevel3-6e2f88c7-moex-00332', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '廠商因變造投標相關文件參與政府採購，而遭採購機關通知將其刊登政府採購公報。下列何者正 確？', '["通知刊登行為係行政罰", "通知刊登行為係警告性質", "通知刊登行為適用5年時效", "通知刊登行為適用10年時效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00333', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '法務部行政執行署各分署之執行人員於查封前，發見義務人之財產業經其他機關查封，下列何者 正確？', '["執行人員得自行決定是否再行查封", "執行人員不得再行查封", "執行人員應請示上級機關再為決定", "執行人員應依不同案情判斷是否再為查封"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00334', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '有關行政程序法聽證規定之敘述，下列何者錯誤？', '["行政機關得於聽證期日前，舉行預備聽證以利程序之進行", "聽證，應作成聽證紀錄", "除別有規定外，行政機關應依聽證紀錄作成行政處分", "對於經過聽證程序所作成之行政處分，其行政救濟程序，免除訴願及其先行程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00335', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '訴願人提起訴願，請求為特定內容之行政處分，在訴願決定作成前，應作為之機關已作成不利於 訴願人之行政處分。受理訴願機關應為如何之處置？', '["應以訴願為不合法，為不受理之決定", "應逕認訴願為無理由，以決定駁回之", "應逕認訴願為有理由者，將原處分撤銷", "應續行訴願程序，對嗣後所為之行政處分併為實體審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00336', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '有關訴願管轄之敘述，下列何者錯誤？', '["對縣政府辦理委辦事件所為之行政處分不服者，向縣政府之直接上級機關提起訴願", "對無隸屬關係之機關辦理受委託事件所為之行政處分不服者，向原委託機關或其直接上級機關 提起訴願", "對有隸屬關係之機關辦理受委任事件所為之行政處分不服者，向原委任機關之直接上級機關提 起訴願", "對受託行使公權力之個人所為之行政處分不服者，向原委託機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00337', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政訴訟訴訟費用之敘述，下列何者錯誤？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣2,000元", "適用通常訴訟程序之事件，按件徵收裁判費新臺幣4,000元", "訴訟費用原則上由敗訴之當事人負擔", "依行政訴訟法第198條為情況判決時，其訴訟費用由敗訴之原告負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00338', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '關於行政訴訟輔佐人之敘述，下列何者錯誤？', '["輔佐人經審判長許可得到場", "人數不得超過2人", "僅限當事人得申請輔佐人到場", "審判長認其不適當得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00339', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '行政機關依法實施即時強制，造成人民損害之補償，下列何者錯誤？', '["該損失補償，以回復原狀為原則，金錢補償為例外", "對於執行機關所為損失補償之決定不服，可依法提起訴願及行政訴訟", "損失補償，應於知有損失後，2年內向執行機關請求", "人民因執行機關依法實施即時強制，致其財產遭受特別損失，原則得請求補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00340', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '公務員因作成或不作成行政處分，不法侵害人民權益者，請求國家賠償，下列何者錯誤？', '["於提起國家賠償前，原則上必須先進行行政爭訟請求救濟", "如行政爭訟程序已開始，民事法院無須停止國家賠償審判程序", "若人民於訴願期間向賠償義務機關表示不服請求協議賠償，致未依限提起訴願者，視為已遵期 提起訴願", "如行政法院判決已認行政處分不違法並予維持者，受理賠償訴訟之民事法院不得再自行審查行 政處分是否違法，而應以訴訟無理由駁回之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00001', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-e0b1f2ed', 'sub-heelevel3-6f0ba476-01', NULL, 'essay', '甲公司在 X1 年 1 月 1 日以$8,000,000 購得一棟辦公大樓，其中土地
成本為$5,000,000，房屋成本為$3,000,000，預估使用年限 15 年，殘
值$250,000。甲公司擬將該大樓以營業租賃出租，將之分類為投資性
不動產，並採公允價值模式衡量。X1 年底該大樓之土地與房屋公允
價值分別為$5,100,000 及$3,200,000；X2 年底大樓之土地與房屋公允
價值分別為$5,150,000 及$3,050,000。X3 年 10 月 1 日，甲公司將該
大樓轉為自用，土地與房屋之公允價值分別為$5,600,000 與
$2,800,000，估計使用年限為 12年，殘值$160,000，採直線法提列折
舊。
試作 X2 年及 X3 年該辦公大樓相關分錄。該辦公大樓對 X3 年當期
損益之影響為多少？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "3919d42dceee", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0802", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
